def _extract_emotional_tone(text: str) -> dict:
    # Basic emotional tone detection
    emotional_keywords = {
        'positive': ['happy', 'joy', 'love', 'excited'],
        'negative': ['sad', 'angry', 'frustrated', 'disappointed'],
        'neutral': ['okay', 'fine', 'neutral']
    }
    
    text_lower = text.lower()
    tone = 'neutral'
    
    for category, keywords in emotional_keywords.items():
        if any(keyword in text_lower for keyword in keywords):
            tone = category
            break
    
    return {
        'detected_tone': tone,
        'intensity': len(re.findall(r'\w+', text)) / 10
    }

def _assess_narrative_complexity(text: str) -> float:
    # Simple narrative complexity metric
    sentence_count = len(re.findall(r'\w+[.!?]', text))
    unique_words = len(set(re.findall(r'\b\w+\b', text.lower())))
    return min(unique_words / (sentence_count + 1), 1.0)

def _detect_identity_transitions(text: str) -> list:
    # Basic identity transition detection
    identity_markers = ['i think', 'from my perspective', 'as a']
    return [marker for marker in identity_markers if marker in text.lower()]

def _calculate_context_coherence(sentiment_map: dict) -> float:
    # Simple coherence scoring
    return (
        sentiment_map['emotional_tone']['intensity'] * 
        sentiment_map['narrative_complexity'] * 
        (len(sentiment_map['identity_shifts']) + 1)
    ) / 3

def _generate_narrative_insight(sentiment_map: dict, context_score: float) -> dict:
    return {
        'timestamp': datetime.now().isoformat(),
        'emotional_analysis': sentiment_map['emotional_tone'],
        'narrative_complexity': sentiment_map['narrative_complexity'],
        'identity_transitions': sentiment_map['identity_shifts'],
        'context_coherence_score': context_score
    }